import{_ as e,o,c as i,a2 as a}from"./chunks/framework.Bix3-HpO.js";const h=JSON.parse('{"title":"API Settings","description":"DinoFeeds API Settings","frontmatter":{"title":"API Settings","description":"DinoFeeds API Settings","weight":10,"extra":{"order":10},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/dinodds/api"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/dinodds/api"}],["meta",{"property":"og:title","content":"API Settings"}],["meta",{"property":"og:description","content":"DinoFeeds API Settings"}],["meta",{"name":"twitter:title","content":"API Settings"}],["meta",{"name":"twitter:description","content":"DinoFeeds API Settings"}]]},"headers":[],"relativePath":"docs/dinodds/api.md","filePath":"docs/dinodds/api.md"}'),s={name:"docs/dinodds/api.md"};function n(d,t,r,c,p,l){return o(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="dinofeeds-api" tabindex="-1">DinoFeeds API <a class="header-anchor" href="#dinofeeds-api" aria-label="Permalink to &quot;DinoFeeds API&quot;">​</a></h1><p>By purchasing any DinOdds package, you get access to DinoFeeds API.</p><h3 id="about-the-api" tabindex="-1">About the API <a class="header-anchor" href="#about-the-api" aria-label="Permalink to &quot;About the API&quot;">​</a></h3><p>DinoFeeds API has been developed to provide an easy solution for displaying betting odds feeds on WordPress websites, specifically through DinOdds plugin.</p><h3 id="api-settings" tabindex="-1">API Settings <a class="header-anchor" href="#api-settings" aria-label="Permalink to &quot;API Settings&quot;">​</a></h3><p>You can control the API settings through your <a href="https://dinomatic.com/account" target="_blank" rel="noreferrer">DinoMatic account</a>.</p><p><img src="https://media.dinomatic.com/images/docs/dinodds/subscription.jpg" alt="DinOdds Subscription"></p><p>Find the subscription you need and click on <strong>Plugin Settings</strong> button, a popup with a form will appear where you can adjust your settings.</p><p><img src="https://media.dinomatic.com/images/docs/dinodds/subscription-details.jpg" alt="DinOdds Subscription Details"></p><h4 id="notes" tabindex="-1">Notes: <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes:&quot;">​</a></h4><ol><li>You can always change the settings for your subscription</li><li>You can select to pull data for only the leagues and the sportsbooks you want</li><li>If a league is out of season, or you don&#39;t promote a sportsbook, it&#39;s recommended to skip them, otherwise, you&#39;ll have additional <strong>unused</strong> data stored in your database</li></ol>',11)])])}const g=e(s,[["render",n]]);export{h as __pageData,g as default};
